<template>
  <div v-if="open" class="sp-overlay" @click.self="close">
      <div class="sp-panel" role="dialog" aria-modal="true" :aria-label="paletteLabel">
        <div class="sp-input-row">
          <i class="fa fa-search sp-input-icon" aria-hidden="true"></i>
          <input
            ref="input"
            v-model="query"
            class="sp-input"
            type="text"
            :placeholder="inputPlaceholder"
            autocomplete="off"
            autocorrect="off"
            spellcheck="false"
            :aria-label="inputLabel"
            @compositionstart="composing = true"
            @compositionend="composing = false"
            @keydown.down="onArrow($event, 1)"
            @keydown.up="onArrow($event, -1)"
            @keydown.left="onModeArrow($event, -1)"
            @keydown.right="onModeArrow($event, 1)"
            @keydown.enter="onEnter($event)"
          />
          <kbd class="sp-esc" @click="close">esc</kbd>
        </div>

        <div class="sp-modes">
          <button
            type="button"
            class="sp-mode"
            :class="{ active: mode === 'ask' }"
            @click="setMode('ask')"
          >✦ Ask</button>
          <button
            type="button"
            class="sp-mode"
            :class="{ active: mode === 'search' }"
            @click="setMode('search')"
          >Search</button>
          <span v-if="semStatus" class="sp-mode-status">{{ semStatus }}</span>
        </div>

        <div ref="results" class="sp-results">
          <!-- Search modes (keyword / smart): a list of navigable results -->
          <template v-if="mode !== 'ask'">
            <template v-if="query.trim() && groups.length">
              <div v-for="g in groups" :key="g.page" class="sp-group">
                <div class="sp-group-label">{{ g.page }}</div>
                <button
                  v-for="r in g.items"
                  :key="r.flatIndex"
                  class="sp-result"
                  :class="{ active: r.flatIndex === activeIndex }"
                  :ref="el => setRowRef(el, r.flatIndex)"
                  @mousemove="activeIndex = r.flatIndex"
                  @click="go(r.route, r.anchor)"
                >
                  <span class="sp-result-title" v-html="r.titleHtml"></span>
                  <span v-if="r.snippetHtml" class="sp-result-snippet" v-html="r.snippetHtml"></span>
                </button>
              </div>
            </template>

            <div v-else-if="query.trim() && semBusy" class="sp-empty">
              {{ semLoading ? 'Loading model…' : 'Searching…' }}
            </div>

            <div v-else-if="query.trim()" class="sp-empty">
              No matches for &ldquo;{{ query.trim() }}&rdquo;.
            </div>

            <div v-else class="sp-group">
              <div class="sp-group-label">Jump to</div>
              <button
                v-for="s in suggestions"
                :key="s.route"
                class="sp-result"
                @click="go(s.route, '')"
              >
                <span class="sp-result-title">{{ s.label }}</span>
              </button>
            </div>
          </template>

          <!-- Ask mode: a generated answer with its sources -->
          <div v-else class="sp-ask">
            <div v-if="!askReady" class="sp-empty">
              Ask isn&rsquo;t set up yet. Deploy the Worker, then set the endpoint.
            </div>
            <template v-else>
              <p v-if="answerText" class="sp-ask-answer">{{ answerText }}</p>
              <div v-else-if="askBusy" class="sp-empty">{{ askStatus }}</div>
              <div v-else-if="askError" class="sp-empty">Something went wrong. Press Enter to try again.</div>
              <div v-else class="sp-empty">Ask anything about Henry, then press Enter.</div>

              <div v-if="citedSources.length && !askBusy" class="sp-ask-sources">
                <div class="sp-group-label">Sources</div>
                <button
                  v-for="s in citedSources"
                  :key="s.id"
                  class="sp-ask-source"
                  @click="go(s.route, s.anchor)"
                >{{ s.page }} › {{ s.title }}</button>
              </div>
            </template>
          </div>
        </div>

        <div class="sp-foot">
          <span><kbd>&larr;</kbd><kbd>&rarr;</kbd> mode</span>
          <span><kbd>&crarr;</kbd> {{ mode === 'ask' ? 'ask' : 'open' }}</span>
          <span v-if="mode !== 'ask'"><kbd>&uarr;</kbd><kbd>&darr;</kbd> move</span>
          <span><kbd>esc</kbd> close</span>
        </div>
      </div>
    </div>
</template>

<script>
import Fuse from 'fuse.js';
import { ensureReady, semanticRank } from '../utils/semanticSearch';
import { askConfigured, askStream } from '../utils/askSite';
import {
  allAskContexts,
  citedSourcesFromAnswer,
  cleanAskContextText,
  retrieveAskContexts,
  stripAnswerCitations,
} from '../utils/askRetrieval';

// Keep in sync with slugify() in scripts/build-search-index.mjs.
function slugify(s) {
  return String(s)
    .replace(/<[^>]+>/g, '')
    .toLowerCase()
    .trim()
    .replace(/[^\w\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .slice(0, 80);
}

// Highlighting/snippet anchoring ignore these so a phrase like "on the machine
// side" keys off "machine"/"side", not the stopwords scattered everywhere.
const STOP = new Set([
  'the', 'a', 'an', 'of', 'on', 'in', 'to', 'is', 'are', 'was', 'were', 'be',
  'and', 'or', 'for', 'with', 'at', 'by', 'from', 'as', 'it', 'i', 'my', 'me',
  'this', 'that', 'how', 'what', 'we', 'you', 'they', 'but', 'so', 'if', 'into',
  'about', 'out', 'up', 'over', 'than', 'then', 'has', 'have', 'had', 'do',
]);

export default {
  name: 'SearchPalette',
  data() {
    return {
      open: false,
      query: '',                       // the active mode's query (bound to the input)
      savedQueries: { search: '', ask: '' }, // kept so switching/reopening restores each mode's text
      items: [],
      fuse: null,
      loaded: false,
      activeIndex: 0,
      rowRefs: {},
      composing: false,   // true while an IME composition is in progress
      mode: 'ask',         // 'search' (lexical-first, RRF hybrid once warm) | 'ask' (RAG answer)
      semHits: [],         // [{ id, score }] from the last semantic rank
      semLoading: false,   // model + vectors warming up
      semQuerying: false,  // a semantic query is in flight
      semError: '',
      askAnswer: '',       // streamed RAG answer text
      askSources: [],      // chunks used as context (shown as source chips)
      askBusy: false,
      askError: '',
      askStatus: '',
      suggestions: [
        { label: 'About', route: '/about' },
        { label: 'Education', route: '/education' },
        { label: 'Experience', route: '/experience' },
        { label: 'Research', route: '/research' },
        { label: 'Projects', route: '/projects' },
        { label: 'CV', route: '/cv' },
      ],
    };
  },
  computed: {
    itemsById() {
      const m = {};
      for (const it of this.items) m[it.id] = it;
      return m;
    },
    semBusy() {
      return this.semLoading || this.semQuerying;
    },
    semStatus() {
      if (this.semError) return 'offline';
      if (this.semLoading) return 'loading model…';
      return '';
    },
    paletteLabel() {
      return this.mode === 'ask' ? 'Ask this site' : 'Search the site';
    },
    inputLabel() {
      return this.mode === 'ask' ? 'Ask question' : 'Search query';
    },
    inputPlaceholder() {
      return this.mode === 'ask' ? 'Ask anything about Henry…' : 'Search the site…';
    },
    askReady() {
      return askConfigured();
    },
    // Answer with the [n] citation markers stripped — the model still emits them
    // (we parse them for the source list), but they read as clutter in the prose.
    answerText() {
      return stripAnswerCitations(this.askAnswer);
    },
    // Show only the sources the model actually cited ([n] markers). We hand the
    // model more context than it needs, but only surface what it used. Falls back
    // to all if it cited nothing parseable.
    citedSources() {
      return citedSourcesFromAnswer(this.askAnswer, this.askSources);
    },
    results() {
      if (this.mode === 'ask') return [];
      const q = this.query.trim();
      if (!q) return [];
      // hybridIds is lexical-only until the semantic model warms (semHits empty),
      // then becomes a fused ranking. So results appear instantly and improve.
      return this.hybridIds(q).map(id => this.itemsById[id]).filter(Boolean).slice(0, 12);
    },
    groups() {
      const out = [];
      const byPage = new Map();
      let fi = 0;
      for (const item of this.results) {
        const titleHtml = this.highlight(item.title);
        // Highlight the literal match when there is one, else a leading snippet,
        // so same-named entries stay distinguishable.
        const snippetHtml = this.snippet(item.body) || this.leadSnippet(item.body);
        const row = { ...item, flatIndex: fi++, titleHtml, snippetHtml };
        if (!byPage.has(item.page)) {
          const g = { page: item.page, items: [] };
          byPage.set(item.page, g);
          out.push(g);
        }
        byPage.get(item.page).items.push(row);
      }
      return out;
    },
    flatList() {
      return this.groups.flatMap(g => g.items);
    },
  },
  watch: {
    query() {
      this.activeIndex = 0;
      // Lazily warm the model on the first real query (so visitors who only open
      // ⌘K and leave never download it), then keep semHits fresh for the hybrid.
      if (this.mode === 'search' && this.query.trim()) {
        this.warmSemantic();
        this.scheduleSemantic();
      }
    },
  },
  mounted() {
    this._semSeq = 0;
    this._askSeq = 0;
    window.addEventListener('keydown', this.onKey);
  },
  unmounted() {
    window.removeEventListener('keydown', this.onKey);
    this.unlockScroll();
  },
  methods: {
    onKey(e) {
      const k = e.key.toLowerCase();
      if ((e.metaKey || e.ctrlKey) && k === 'k') {
        e.preventDefault();
        this.toggle();
      } else if (e.key === 'Escape' && this.open) {
        this.close();
      } else if (e.key === '/' && !this.open && !this.isTyping(e)) {
        e.preventDefault();
        this.openPalette();
      }
    },
    isTyping(e) {
      const t = e.target;
      return t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.isContentEditable);
    },
    async loadIndex() {
      if (this.loaded) return;
      try {
        const res = await fetch('/assets/search-index.json', { cache: 'no-cache' });
        this.items = await res.json();
        this.fuse = new Fuse(this.items, {
          keys: [{ name: 'title', weight: 0.7 }, { name: 'body', weight: 0.3 }],
          threshold: 0.3,
          ignoreLocation: true,
          minMatchCharLength: 2,
        });
        this.loaded = true;
      } catch (err) {
        console.error('search index load failed:', err);
      }
    },
    toggle() {
      this.open ? this.close() : this.openPalette();
    },
    openPalette() {
      // Reopen in whatever state the palette was last left (mode, query, results, answer);
      // it only resets on a full page refresh. No state is cleared here.
      this.open = true;
      this.loadIndex();
      this.lockScroll();
      this.warmSemantic();
      this.$nextTick(() => this.$refs.input && this.$refs.input.focus());
    },
    // Public: open straight into Ask mode. With a prefill, runs the question
    // immediately (used by the header "Ask" entry and the homepage ask-bar).
    openAsk(prefill) {
      this.open = true;
      this.loadIndex();
      this.lockScroll();
      this.mode = 'ask';
      this.activeIndex = 0;
      this.askAnswer = '';
      this.askSources = [];
      this.askError = '';
      this.warmSemantic();
      if (prefill && prefill.trim()) {
        this.query = prefill.trim();
        this.$nextTick(() => this.askQuestion());
      } else {
        this.query = '';
        this.$nextTick(() => this.$refs.input && this.$refs.input.focus());
      }
    },
    close() {
      // Keep query/mode/results/answer so reopening restores them (until a page refresh).
      this.open = false;
      this.unlockScroll();
    },
    move(dir) {
      const n = this.flatList.length;
      if (!n) return;
      this.activeIndex = (this.activeIndex + dir + n) % n;
      this.$nextTick(() => {
        const el = this.rowRefs[this.activeIndex];
        if (el && el.scrollIntoView) el.scrollIntoView({ block: 'nearest' });
      });
    },
    // IME guard: while composing (e.g. picking a pinyin candidate), Enter and
    // the arrows belong to the input method, not the palette. keyCode 229 and
    // isComposing both flag composition; the data flag is a cross-browser
    // backstop since the commit keydown fires before compositionend.
    isComposing(e) {
      return this.composing || e.isComposing || e.keyCode === 229;
    },
    onEnter(e) {
      if (this.isComposing(e)) return;
      e.preventDefault();
      if (this.mode === 'ask') this.askQuestion();
      else this.choose();
    },
    onArrow(e, dir) {
      if (this.isComposing(e)) return;
      e.preventDefault();
      this.move(dir);
    },
    onModeArrow(e, dir) {
      if (this.isComposing(e)) return;
      e.preventDefault();
      this.setMode(dir < 0 ? 'ask' : 'search');
    },
    choose() {
      const target = this.flatList[this.activeIndex];
      if (target) this.go(target.route, target.anchor);
    },
    setRowRef(el, i) {
      if (el) this.rowRefs[i] = el;
    },
    go(route, anchor) {
      const samePage = this.$route.path === route;
      this.close();
      if (!samePage) this.$router.push(route);
      this.$nextTick(() => this.scrollTo(anchor, 0));
    },
    scrollTo(anchor, attempt) {
      this.assignAnchors();
      if (!anchor) {
        window.scrollTo({ top: 0, behavior: 'smooth' });
        return;
      }
      const el = document.getElementById(anchor);
      if (el) {
        this.scrollTargetFor(el).scrollIntoView({ behavior: 'smooth', block: 'start' });
        this.flash(el);
        return;
      }
      if (attempt < 20) setTimeout(() => this.scrollTo(anchor, attempt + 1), 120);
    },
    // Land on the entry's visual top, not the title: research/projects keep the date label
    // at the page top (top of .timeline-event); education/experience keep the school /
    // company logo at the top (top of the entry <section>).
    scrollTargetFor(el) {
      const te = el.closest('.timeline-event');
      if (te) return te;
      if (el.matches && el.matches('li.title')) {
        const sec = el.closest('section');
        if (sec) return sec;
      }
      return el;
    },
    // Assign stable ids to the current page's headings, mirroring the slugs the
    // build-time extractor produced, so results can deep-link to a section.
    assignAnchors() {
      const root = document.querySelector('.content-container');
      if (!root) return;
      // Timeline pages anchor on their entry titles (school / role); every other
      // page anchors on its h2/h3 headings. Must mirror the build-time extractor.
      const useEntries = !!root.querySelector('li.title');
      const els = useEntries
        ? root.querySelectorAll('li.title')
        : root.querySelectorAll('h2, h3');
      const seen = new Set();
      els.forEach((el) => {
        const base = slugify(el.textContent);
        if (!base) return;
        let slug = base;
        let n = 2;
        while (seen.has(slug)) slug = `${base}-${n++}`;
        seen.add(slug);
        el.id = slug;
      });
    },
    flash(el) {
      el.classList.add('search-flash');
      setTimeout(() => el.classList.remove('search-flash'), 1700);
    },
    lockScroll() {
      this._prevOverflow = document.body.style.overflow;
      document.body.style.overflow = 'hidden';
    },
    unlockScroll() {
      document.body.style.overflow = this._prevOverflow || '';
    },
    escapeHtml(s) {
      return String(s).replace(/[&<>"]/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]));
    },
    tokens() {
      const all = this.query.toLowerCase().split(/\s+/)
        .map(t => t.replace(/[^\w]+/g, '')) // strip punctuation, e.g. "hobbies?" -> "hobbies"
        .filter(t => t.length >= 2);
      const meaningful = all.filter(t => !STOP.has(t));
      // Fall back to all words only if the query is nothing but stopwords.
      return meaningful.length ? meaningful : all;
    },
    highlight(text) {
      let safe = this.escapeHtml(text);
      // Mark literal matches in both modes; semantic-only hits simply contain no
      // query tokens, so nothing gets marked there anyway.
      for (const t of this.tokens()) {
        // Match at a word start only, so "on" highlights the word "on" but not
        // the "on" inside "reasons"; a prefix match still catches "machine(s)".
        const re = new RegExp(`\\b(${t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})`, 'ig');
        safe = safe.replace(re, '<mark>$1</mark>');
      }
      return safe;
    },
    snippet(body) {
      const lower = body.toLowerCase();
      // Anchor on the most specific (longest) matching word, not the first token,
      // so the snippet lands on the meaningful part of the phrase.
      let pos = -1;
      for (const t of [...this.tokens()].sort((a, b) => b.length - a.length)) {
        const m = new RegExp(`\\b${t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}`, 'i').exec(lower);
        if (m) { pos = m.index; break; }
      }
      if (pos < 0) return '';
      const start = Math.max(0, pos - 40);
      let s = body.slice(start, start + 170);
      if (start > 0) s = `…${s}`;
      if (start + 170 < body.length) s = `${s}…`;
      return this.highlight(s);
    },
    // Plain leading snippet for semantic hits that share no literal words.
    leadSnippet(body) {
      let s = body.slice(0, 170);
      if (body.length > 170) s = `${s}…`;
      return this.highlight(s);
    },
    setMode(m) {
      if (this.mode === m) return;
      // Stash the current mode's text and restore the other mode's, so each keeps its own
      // content. The Ask answer/sources are NOT cleared here — only a new question clears them.
      this.savedQueries[this.mode] = this.query;
      this.mode = m;
      this.query = this.savedQueries[m] || '';
      this.activeIndex = 0;
      if (m === 'search') {
        if (this.query.trim()) { this.warmSemantic(); this.scheduleSemantic(); }
      } else {
        this.warmSemantic(); // Ask retrieves with the same embeddings
      }
    },
    // Retrieve the top context chunks for a question, reusing the hybrid ranker.
    async retrieveContexts(q, n = 8) {
      return retrieveAskContexts(q, n, this.items);
    },
    async askQuestion() {
      const q = this.query.trim();
      if (!q || !this.askReady) return;
      const seq = ++this._askSeq;
      this.askBusy = true;
      this.askError = '';
      this.askAnswer = '';
      this.askSources = [];
      try {
        this.askStatus = 'Thinking…';
        // Send the whole site (it's tiny) rather than a retrieved top-k, so the answer
        // never misses a relevant section. Sources shown are whatever the model cites.
        const contexts = await allAskContexts(this.items);
        if (seq !== this._askSeq) return;
        this.askSources = contexts;
        this.askStatus = 'Thinking…';
        // Strip retrieval-only tags (category keywords + expanded year lists) so
        // the model sees clean content, not keyword noise it might weave into answers.
        const payload = contexts.map(c => ({ page: c.page, title: c.title, text: cleanAskContextText(c.body) }));
        for await (const tok of askStream(q, payload)) {
          if (seq !== this._askSeq) return;
          this.askAnswer += tok;
        }
      } catch (e) {
        if (seq === this._askSeq) this.askError = 'error';
        console.error('ask failed:', e);
      } finally {
        if (seq === this._askSeq) this.askBusy = false;
      }
    },
    // Reciprocal-rank fusion of the lexical (Fuse) and semantic lists. Lexical
    // nails short/exact queries ("work" -> Work Experience), semantic adds
    // conceptual recall; an off-topic query matches neither, so it stays empty.
    hybridIds(q) {
      const K = 60;
      // Lexical is weighted higher: for exact/short terms it is far more precise
      // than the small embedding model, which is noisy on 1-2 word queries.
      const W_LEX = 2, W_SEM = 1;
      const score = new Map();
      const add = (ids, w) => ids.forEach((id, i) => score.set(id, (score.get(id) || 0) + w / (K + i)));
      if (this.fuse) add(this.fuse.search(q).slice(0, 20).map(r => r.item.id), W_LEX);
      add(this.semHits.map(h => h.id), W_SEM); // already floor-filtered + ranked
      return [...score.entries()].sort((a, b) => b[1] - a[1]).map(([id]) => id);
    },
    async warmSemantic() {
      if (this._semWarmed || this.semLoading) return;
      this.semLoading = true;
      this.semError = '';
      try {
        await ensureReady();
        this._semWarmed = true;
      } catch (e) {
        this.semError = 'offline';
        console.error('semantic warm-up failed:', e);
      } finally {
        this.semLoading = false;
      }
    },
    scheduleSemantic() {
      clearTimeout(this._semDebounce);
      this._semDebounce = setTimeout(() => this.runSemantic(), 250);
    },
    async runSemantic() {
      const q = this.query.trim();
      if (!q) { this.semHits = []; return; }
      const seq = ++this._semSeq;
      this.semQuerying = true;
      try {
        const hits = await semanticRank(q, 12);
        if (seq === this._semSeq) { this.semHits = hits; this.semError = ''; }
      } catch (e) {
        if (seq === this._semSeq) { this.semHits = []; this.semError = 'offline'; }
        console.error('semantic search failed:', e);
      } finally {
        if (seq === this._semSeq) this.semQuerying = false;
      }
    },
  },
};
</script>

